func profileChartLabels(pts []ProfileChartDataPoint) []string {
	labels := make([]string, len(pts))
	for i, p := range pts {
		labels[i] = p.Label
	}
	return labels
}

func profileChartValues(pts []ProfileChartDataPoint) []float64 {
	vals := make([]float64, len(pts))
	for i, p := range pts {
		vals[i] = p.Value
	}
	return vals
}

func formatCost(microcents int64, currency string) string {
	symbol := "$"
	switch currency {
	case "EUR":
		symbol = "€"
	case "GBP":
		symbol = "£"
	case "JPY":
		symbol = "¥"
	}
	return fmt.Sprintf("%s%.6f", symbol, float64(microcents)/1_000_000)
}

func formatBudget(v *int64, currency string) string {
	if v == nil {
		return "Illimité"
	}
	return formatCost(*v, currency)
}

